import"./main-D56FifXV.js";const i={init:async()=>{try{const n=await(await fetch("/js/data/tips.json")).json();if(n.length>0){const t=n[Math.floor(Math.random()*n.length)],o=document.getElementById("tip-of-day-card"),a=document.getElementById("tip-content");if(!o||!a)return;const c=localStorage.getItem("wptoolbox_lang")==="ar";a.textContent=c&&t.fact.ar||t.fact.en,o.classList.remove("hidden"),window._currentTip=t}}catch(e){console.error("Failed to load tips",e)}window.addEventListener("languageChanged",e=>{const n=e.detail.lang==="ar",t=document.getElementById("tip-content");t&&window._currentTip&&(t.textContent=n&&window._currentTip.fact.ar||window._currentTip.fact.en)})}};document.readyState==="loading"?document.addEventListener("DOMContentLoaded",i.init):i.init();
